/**
 * NodeTrace trajectory exporter — the NET-NEW RL layer.
 *
 * Turns a production `CaptureResult` (the observe/act/extract loop's honest output) into the
 * `NodeTrajectory` shape that downstream SFT / DPO / RLVR pipelines consume, and serializes a batch
 * to JSONL (one trajectory per line). This file is HAND-MAINTAINED net-new code: it is NOT listed in
 * MANIFEST.json and is NOT re-exported from the generated index.ts (both are regenerated by
 * scripts/extract-from-noderoom.mjs and would clobber any edit). It is exposed via the package.json
 * "./trajectory" subpath export instead. It imports ONLY types from the generated "./types".
 *
 * Design invariants (root-caused, each enforced below):
 *  - HONEST_STATUS: capture.ok===false (or error / a phase==="Error" / status==="risk" step) yields a
 *    FAILURE trajectory. `error` is preserved, `truncated` flags it, and no reward is coerced positive.
 *    The failure trajectory is the valuable RL signal — we never fake success.
 *  - HONEST_SCORES: the product-side reward components (taskSuccess, evidenceGrounding, visualQuality,
 *    noClobber, safety, costEfficiency*, latencyEfficiency*) are NOT fabricated. Whatever the caller
 *    supplies is carried verbatim; anything unsupplied is 0 AND recorded in `labels` as
 *    "unscored:<field>" — never a hardcoded floor. Only the per-step PROCESS reward (from status) is
 *    trace-derivable, and its `reason` explicitly states it is a heuristic.
 *  - DETERMINISTIC: no Date.now / Math.random / new Date. Any derived id is a sorted-key FNV-1a hash of
 *    stable inputs. Same input twice => byte-identical JSONL.
 *  - NO-LEAK / BOUNDED: `screenshotPng` (Uint8Array) bytes are NEVER inlined. Each screenshot-bearing
 *    step contributes a path/ref to `outputs.screenshots` and the bytes are dropped from the emitted
 *    step. JSONL emits exactly one trajectory per line.
 */
import type { CaptureResult, CaptureStep, ActStep, NormBox } from "./types";

/* ------------------------------------------------------------------------------------------------ *
 * Net-new RL types (re-stated here; only CaptureResult/CaptureStep/ActStep/NormBox are imported).   *
 * ------------------------------------------------------------------------------------------------ */

/** A tool call the agent made (host-level action, not a browser primitive). */
export interface ToolCallAction { kind: "tool_call"; tool: string; args: unknown }
/** A file the agent edited (coding-host action). */
export interface FileEditAction { kind: "file_edit"; files: string[] }
/** A test/benchmark command the agent ran. */
export interface TestRunAction { kind: "test_run"; command: string }

/** Every action a trajectory step can carry: a browser ActStep or a host-level action. */
export type TraceAction = ActStep | ToolCallAction | FileEditAction | TestRunAction;

/** Per-step trace-derivable process reward. `reason` always discloses it is a heuristic. */
export interface ProcessReward { process: number; reason: string }

/** Per-step cost ledger. All fields optional — only carried when known. */
export interface StepCost { tokensIn?: number; tokensOut?: number; latencyMs?: number; usd?: number }

/** A CaptureStep promoted with RL fields. Note: the emitted form NEVER contains screenshotPng bytes. */
export interface NodeTraceStep extends CaptureStep {
  episodeId: string;
  stepIndex: number;
  action: TraceAction;
  reward?: ProcessReward;
  cost?: StepCost;
}

/** Where a trajectory started — provenance for reproducibility. */
export interface TrajectoryInitialState {
  gitCommit?: string;
  url?: string;
  artifactRefs?: string[];
  contextPackHash?: string;
}

/** Collected artifacts the run produced. Screenshots are PATHS/REFS, never inlined bytes. */
export interface TrajectoryOutputs {
  files: string[];
  receipts: string[];
  screenshots: string[];
  videos: string[];
}

/** The product-supplied + trace-derived reward summary (see reward-design.md). */
export interface NodeRewardSummary {
  taskSuccess: number;
  evidenceGrounding: number;
  visualQuality: number;
  noClobber: number;
  costEfficiency: number;
  latencyEfficiency: number;
  safety: number;
  total: number;
  labels: string[];
  failureCategories: string[];
}

/** The unit NodeRL records, scores, and exports. */
export interface NodeTrajectory {
  trajectoryId: string;
  environment: string;
  agentHost: string;
  goal: string;
  model?: string;
  initialState: TrajectoryInitialState;
  steps: NodeTraceStep[];
  outputs: TrajectoryOutputs;
  rewards?: NodeRewardSummary;
  truncated?: boolean;
  /**
   * HONEST_STATUS: the verbatim failure message from a failed capture (CaptureResult.error), preserved
   * so the failure trajectory carries its real RL signal. Absent on successful runs. Never synthesized.
   */
  error?: string;
}

/* ------------------------------------------------------------------------------------------------ *
 * Deterministic id helper — sorted-key FNV-1a hash. No Date / Math.random.                          *
 * ------------------------------------------------------------------------------------------------ */

/** FNV-1a 32-bit over a UTF-8 string. Pure, deterministic. */
function fnv1a(input: string): number {
  let hash = 0x811c9dc5;
  for (let i = 0; i < input.length; i++) {
    hash ^= input.charCodeAt(i) & 0xff;
    // Mix higher code units too so multi-byte chars still contribute deterministically.
    const hi = input.charCodeAt(i) >> 8;
    if (hi) hash ^= hi;
    hash = Math.imul(hash, 0x01000193);
  }
  return hash >>> 0;
}

/**
 * Deterministic id from stable key/value pairs. Keys are sorted so call-site ordering is irrelevant
 * (DETERMINISTIC: same logical inputs => identical id). Values are JSON-stringified for stability.
 */
export function deterministicId(prefix: string, fields: Record<string, unknown>): string {
  const canonical = Object.keys(fields)
    .sort()
    .map((k) => `${k}=${JSON.stringify(fields[k] ?? null)}`)
    .join("&");
  const h = fnv1a(`${prefix}|${canonical}`).toString(16).padStart(8, "0");
  // Two rounds widen the id space without time/random; still a pure function of inputs.
  const h2 = fnv1a(`${h}|${canonical}|${prefix}`).toString(16).padStart(8, "0");
  return `${prefix}_${h}${h2}`;
}

/* ------------------------------------------------------------------------------------------------ *
 * toTrajectory — CaptureResult -> NodeTrajectory.                                                   *
 * ------------------------------------------------------------------------------------------------ */

export interface ToTrajectoryMeta {
  environment: string;
  agentHost: string;
  goal: string;
  model?: string;
  initialState?: TrajectoryInitialState;
  /** Explicit id; otherwise derived deterministically from stable inputs. */
  trajectoryId?: string;
  /** Explicit episode id; otherwise derived deterministically. */
  episodeId?: string;
  /** Per-step action override (index-aligned to capture.steps). Unset entries fall back to inference. */
  actions?: (TraceAction | undefined)[];
  /** Product-side reward components (carried verbatim, never fabricated). Attached as trajectory.rewards. */
  rewardComponents?: Partial<NodeRewardSummary>;
  /** Per-step cost override (index-aligned). Unset entries fall back to latency-from-ms. */
  costs?: (StepCost | undefined)[];
  /** Maps a step index to a stored screenshot path/ref. Used to externalize screenshotPng bytes. */
  screenshotPathFor?: (stepIndex: number) => string;
  /** Optional reward formula for summarizeReward when rewardComponents are supplied. */
  rewardFormula?: RewardFormula;
}

/**
 * Honest signal: is this a failure capture? True if ok===false, an error is set, or any step is a
 * hard-error / risk step. Used to flag truncation and to refuse positive reward coercion.
 */
function captureFailed(capture: CaptureResult): boolean {
  if (capture.ok === false) return true;
  if (capture.error) return true;
  return capture.steps.some((s) => s.phase === "Error" || s.status === "risk");
}

/**
 * Infer an honest default action when the caller did not supply one. We DO NOT invent specifics we
 * cannot know — Observe/Extract map to a coarse scroll/observe browser primitive, Error maps to a
 * "scroll" no-op (the phase/label/status carry the real signal). When the step looks like a host-level
 * phase we still keep it as a browser ActStep default rather than fabricating a tool/file/test action.
 */
function inferAction(step: CaptureStep): TraceAction {
  const phase = step.phase;
  if (phase === "Act") {
    // Best-effort: a generic click is the most common act; honest because target is left undefined.
    return { kind: "click" };
  }
  // Observe / Extract / Error / anything else: a scroll is the honest neutral browser primitive.
  return { kind: "scroll" };
}

/**
 * Trace-derivable PROCESS reward from a step's status. This is the ONLY reward component the exporter
 * computes itself, and the reason string always discloses it is a heuristic (HONEST_SCORES).
 *   ok   -> +1   warn -> 0   risk -> -1
 */
function processRewardFor(step: CaptureStep): ProcessReward {
  let process: number;
  let qualifier: string;
  switch (step.status) {
    case "ok":
      process = 1;
      qualifier = "status=ok";
      break;
    case "warn":
      process = 0;
      qualifier = "status=warn";
      break;
    case "risk":
      process = -1;
      qualifier = "status=risk";
      break;
    default:
      process = 0;
      qualifier = `status=${String(step.status)}`;
      break;
  }
  return {
    process,
    reason: `heuristic: per-step process reward derived from CaptureStep.status (${qualifier}); not a product score`,
  };
}

/** Build the per-step cost. Caller override wins; otherwise carry latency from ms when present. */
function costFor(step: CaptureStep, override: StepCost | undefined): StepCost | undefined {
  if (override) return override;
  if (typeof step.ms === "number") return { latencyMs: step.ms };
  return undefined;
}

/**
 * Map a CaptureResult to a NodeTrajectory.
 * - stepIndex is 0..n sequential.
 * - screenshotPng bytes are externalized to outputs.screenshots and DROPPED from the emitted step.
 * - failure captures produce an honest failure trajectory (truncated=true, error preserved).
 */
export function toTrajectory(capture: CaptureResult, meta: ToTrajectoryMeta): NodeTrajectory {
  const initialState: TrajectoryInitialState = {
    ...(meta.initialState ?? {}),
  };
  // The capture's terminal url is part of the starting/landing provenance if not otherwise set.
  if (initialState.url === undefined && capture.url) initialState.url = capture.url;

  const failed = captureFailed(capture);

  const trajectoryId =
    meta.trajectoryId ??
    deterministicId("traj", {
      goal: meta.goal,
      agentHost: meta.agentHost,
      environment: meta.environment,
      gitCommit: meta.initialState?.gitCommit ?? null,
      url: capture.url,
      stepCount: capture.steps.length,
    });

  const episodeId =
    meta.episodeId ??
    deterministicId("ep", {
      trajectoryId,
      goal: meta.goal,
      agentHost: meta.agentHost,
      stepCount: capture.steps.length,
    });

  const screenshots: string[] = [];

  const steps: NodeTraceStep[] = capture.steps.map((rawStep, i) => {
    // NO-LEAK: strip screenshotPng bytes; record a path/ref instead.
    const { screenshotPng, ...rest } = rawStep;
    if (screenshotPng !== undefined) {
      const ref = meta.screenshotPathFor
        ? meta.screenshotPathFor(i)
        : `${episodeId}/step-${i}.png`;
      screenshots.push(ref);
    }

    const action: TraceAction = meta.actions?.[i] ?? inferAction(rawStep);

    const step: NodeTraceStep = {
      ...rest,
      episodeId,
      stepIndex: i,
      action,
      reward: processRewardFor(rawStep),
    };
    const cost = costFor(rawStep, meta.costs?.[i]);
    if (cost) step.cost = cost;
    return step;
  });

  // outputs: receipts/files/videos are product-supplied artifacts; the exporter only owns screenshots
  // (which it externalizes from the trace). The other arrays start empty and are populated by callers
  // who know about downloaded deliverables — we never invent them.
  const outputs: TrajectoryOutputs = {
    files: [],
    receipts: [],
    screenshots,
    videos: [],
  };

  const trajectory: NodeTrajectory = {
    trajectoryId,
    environment: meta.environment,
    agentHost: meta.agentHost,
    goal: meta.goal,
    ...(meta.model !== undefined ? { model: meta.model } : {}),
    initialState,
    steps,
    outputs,
  };

  // HONEST_STATUS: failure captures are flagged truncated AND the verbatim error is preserved on the
  // trajectory (never cleared, never coerced to success). Mark truncated so downstream pipelines treat
  // this as a non-terminal/failed episode; the failure trajectory is the valuable RL signal.
  if (failed) trajectory.truncated = true;
  if (capture.error) trajectory.error = capture.error;

  // Attach a reward summary built honestly from the supplied components + trace-derived failure signals.
  trajectory.rewards = summarizeReward(trajectory, meta.rewardComponents, meta.rewardFormula, capture);

  return trajectory;
}

/* ------------------------------------------------------------------------------------------------ *
 * summarizeReward — carries supplied components honestly; never fabricates a product score.         *
 * ------------------------------------------------------------------------------------------------ */

/** The seven scored components (everything on NodeRewardSummary except total/labels/failureCategories). */
const REWARD_COMPONENTS = [
  "taskSuccess",
  "evidenceGrounding",
  "visualQuality",
  "noClobber",
  "costEfficiency",
  "latencyEfficiency",
  "safety",
] as const;
type RewardComponentKey = (typeof REWARD_COMPONENTS)[number];

/** A reward aggregation formula. Receives the resolved components and returns the headline total. */
export type RewardFormula = (components: Record<RewardComponentKey, number>) => number;

/**
 * Documented DEFAULT formula. Generic-only (no per-task answer-key writers — see anti-cheat-doctrine):
 * a simple mean of the seven components. This is intentionally boring; product evals supply their own
 * weighted formula (see reward-design.md examples) when they have one.
 */
export const defaultRewardFormula: RewardFormula = (c) => {
  const sum = REWARD_COMPONENTS.reduce((acc, k) => acc + c[k], 0);
  return sum / REWARD_COMPONENTS.length;
};

/**
 * Build a NodeRewardSummary.
 *  - Each component the caller supplies (a finite number) is carried VERBATIM.
 *  - Each component NOT supplied is set to 0 AND a label "unscored:<field>" is added. Never a floor.
 *  - `total` = formula(resolvedComponents); supplied formula or the documented default.
 *  - `failureCategories` are derived from HONEST signals only (capture.error, "risk"/"Error" steps,
 *    repeated tool errors). NEVER fabricated.
 * The optional `capture` argument lets us read raw error text + step phases for failure categorization;
 * when omitted we fall back to the trajectory's own steps.
 */
export function summarizeReward(
  trajectory: NodeTrajectory,
  components?: Partial<NodeRewardSummary>,
  formula?: RewardFormula,
  capture?: CaptureResult,
): NodeRewardSummary {
  const supplied = components ?? {};
  const labels: string[] = Array.isArray(supplied.labels) ? [...supplied.labels] : [];

  const resolved = {} as Record<RewardComponentKey, number>;
  for (const key of REWARD_COMPONENTS) {
    const v = supplied[key];
    if (typeof v === "number" && Number.isFinite(v)) {
      resolved[key] = v;
    } else {
      resolved[key] = 0;
      labels.push(`unscored:${key}`);
    }
  }

  // Derive failure categories from honest signals. Start from any supplied categories, then add ours.
  const failureCategories: string[] = Array.isArray(supplied.failureCategories)
    ? [...supplied.failureCategories]
    : [];

  const steps = trajectory.steps;
  const hadRisk = steps.some((s) => s.status === "risk");
  const hadErrorPhase = steps.some((s) => s.phase === "Error");
  const captureError = capture?.error;

  if (captureError) failureCategories.push("capture_error");
  if (hadErrorPhase) failureCategories.push("error_phase_step");
  if (hadRisk) failureCategories.push("risk_step");
  if (trajectory.truncated) failureCategories.push("truncated");

  // Repeated tool/act error heuristic: 2+ steps with negative process reward.
  const negativeSteps = steps.filter((s) => (s.reward?.process ?? 0) < 0).length;
  if (negativeSteps >= 2) failureCategories.push("repeated_step_error");

  // total via supplied formula or the documented default mean.
  const total = (formula ?? defaultRewardFormula)(resolved);

  return {
    taskSuccess: resolved.taskSuccess,
    evidenceGrounding: resolved.evidenceGrounding,
    visualQuality: resolved.visualQuality,
    noClobber: resolved.noClobber,
    costEfficiency: resolved.costEfficiency,
    latencyEfficiency: resolved.latencyEfficiency,
    safety: resolved.safety,
    total,
    labels: dedupe(labels),
    failureCategories: dedupe(failureCategories),
  };
}

function dedupe(xs: string[]): string[] {
  // Stable de-dup preserving first-seen order (DETERMINISTIC: no Set-iteration surprises across engines —
  // insertion order is preserved by construction).
  const seen = new Set<string>();
  const out: string[] = [];
  for (const x of xs) {
    if (!seen.has(x)) {
      seen.add(x);
      out.push(x);
    }
  }
  return out;
}

/* ------------------------------------------------------------------------------------------------ *
 * toJSONL — one trajectory per line, stable key order, no inlined bytes.                            *
 * ------------------------------------------------------------------------------------------------ */

/**
 * Stable-key serializer: recursively rebuilds objects with sorted keys so the same logical trajectory
 * always serializes byte-identically (DETERMINISTIC). Arrays keep their order. Defensive NO-LEAK guard:
 * any stray Uint8Array / ArrayBuffer / Buffer is replaced with a "<bytes:n omitted>" marker rather than
 * being inlined — toTrajectory already strips screenshotPng, this is belt-and-suspenders.
 */
function stableReplace(value: unknown): unknown {
  if (value === null || typeof value !== "object") return value;
  if (value instanceof Uint8Array) return `<bytes:${value.byteLength} omitted>`;
  if (value instanceof ArrayBuffer) return `<bytes:${value.byteLength} omitted>`;
  // Node Buffer is a Uint8Array subclass, so the check above already covers it.
  if (Array.isArray(value)) return value.map(stableReplace);
  const obj = value as Record<string, unknown>;
  const out: Record<string, unknown> = {};
  for (const key of Object.keys(obj).sort()) {
    out[key] = stableReplace(obj[key]);
  }
  return out;
}

/**
 * Serialize a batch of trajectories to JSONL.
 *  - Exactly ONE trajectory per line.
 *  - Stable (sorted) key order so output is byte-identical for identical input.
 *  - No inlined image bytes (toTrajectory strips them; stableReplace is the defensive backstop).
 *
 * Trailing-newline policy: the returned string ENDS WITH a single "\n" (so each line — including the
 * last — is newline-terminated, which is what line-oriented readers / `wc -l` / streaming JSONL parsers
 * expect). An empty input yields the empty string "" (no spurious newline).
 */
export function toJSONL(trajectories: NodeTrajectory[]): string {
  if (trajectories.length === 0) return "";
  return trajectories.map((t) => JSON.stringify(stableReplace(t))).join("\n") + "\n";
}
